                // forcibly kill it. This is BY DESIGN in .NET 8: cooperative
                // cancellation means your code must check the token.
                Console.Error.WriteLine(
                    "WARNING: Worker did not stop within timeout. " +
                    "Ensure all blocking calls accept CancellationToken.");
            }
        }
    }

    public void Dispose()
    {
        _cts.Cancel();
        _workerTask?.Wait(TimeSpan.FromSeconds(2));
        _cts.Dispose();
        GC.SuppressFinalize(this);
    }

